"use client";

import React, { Component, Suspense, useCallback, useEffect, useMemo, useRef, useState, type ErrorInfo, type ReactNode } from "react";
import { addAfterEffect, Canvas, useFrame, useThree } from "@react-three/fiber";
import {
  ContactShadows,
  Html,
  OrbitControls,
  PerspectiveCamera,
} from "@react-three/drei";
import { Eye, User } from "lucide-react";
import type { OrbitControls as OrbitControlsImpl } from "three-stdlib";
import * as THREE from "three";

import {
  buildPlanner3DSceneDocument,
  mmToWorld,
  type Planner3DItem,
  type Planner3DSceneDocument,
  type PlannerDocument,
} from "./types";
import { FOCSS_3D_COLORS } from "./viewerMaterials";
import { logClientError } from "@/lib/errorLogger";

interface Planner3DViewerProps {
  document: PlannerDocument;
  className?: string;
}

interface WebGLProbeResult {
  ok: boolean;
  renderer: string | null;
  context: "webgl2" | "webgl" | null;
}

type ViewerCameraMode = "orbit" | "walk";

interface OrbitPose {
  position: [number, number, number];
  target: [number, number, number];
}

interface WalkPose {
  position: [number, number, number];
  rotation: [number, number];
}

interface CameraMemory {
  sceneSignature: string;
  orbit?: OrbitPose;
  walk?: WalkPose;
}

export interface SceneMetrics {
  target: [number, number, number];
  defaultOrbitPosition: [number, number, number];
  defaultWalkPosition: [number, number, number];
  walkEyeHeight: number;
  roomHalfWidthWorld: number;
  roomHalfDepthWorld: number;
  roomHeightWorld: number;
  maxSpanWorld: number;
  cameraFar: number;
  fogNear: number;
  fogFar: number;
  shadowScale: number;
  shadowFar: number;
  orbitMinDistance: number;
  orbitMaxDistance: number;
  labelPosition: [number, number, number];
}

const UP_VECTOR = new THREE.Vector3(0, 1, 0);

function clamp(value: number, min: number, max: number) {
  if (min > max) return (min + max) / 2;
  return Math.min(max, Math.max(min, value));
}

function probeWebGL(): WebGLProbeResult {
  if (typeof document === "undefined") {
    return { ok: false, renderer: null, context: null };
  }

  const canvas = document.createElement("canvas");
  const contexts: Array<"webgl2" | "webgl"> = ["webgl2", "webgl"];

  for (const contextName of contexts) {
    const gl = canvas.getContext(contextName) as WebGLRenderingContext | WebGL2RenderingContext | null;
    if (!gl) continue;

    let renderer = "WebGL available";
    const debugInfo = gl.getExtension("WEBGL_debug_renderer_info");
    if (debugInfo) {
      renderer = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) as string;
    }
    return { ok: true, renderer, context: contextName };
  }

  return { ok: false, renderer: null, context: null };
}

function resolveItemColor(item: Planner3DItem) {
  if (item.color) return item.color;
  const category = item.category.toLowerCase();
  if (category.includes("storage")) return FOCSS_3D_COLORS.bronze800;
  if (category.includes("seat") || category.includes("sofa")) return FOCSS_3D_COLORS.bronze500;
  if (category.includes("table")) return FOCSS_3D_COLORS.ecru400;
  if (category.includes("desk") || category.includes("work")) return FOCSS_3D_COLORS.darkMidnightBlue350;
  return FOCSS_3D_COLORS.bronze700;
}

function getSceneSignature(sceneDocument: Planner3DSceneDocument) {
  return [
    sceneDocument.id,
    sceneDocument.room.widthMm,
    sceneDocument.room.depthMm,
    sceneDocument.room.wallHeightMm,
    sceneDocument.room.wallThicknessMm,
    sceneDocument.room.floorThicknessMm,
    sceneDocument.items
      .map(
        (item) =>
          `${item.id}:${item.centerMm.xMm}:${item.centerMm.yMm}:${item.sizeMm.widthMm}:${item.sizeMm.depthMm}:${item.sizeMm.heightMm}:${item.rotationDeg ?? 0}`,
      )
      .join("|"),
  ].join(";");
}

function getItemBounds(room: Planner3DSceneDocument["room"], item: Planner3DItem) {
  const halfWidth = mmToWorld(room.widthMm) / 2;
  const halfDepth = mmToWorld(room.depthMm) / 2;
  const width = mmToWorld(item.sizeMm.widthMm);
  const depth = mmToWorld(item.sizeMm.depthMm);
  const height = mmToWorld(item.sizeMm.heightMm);
  const centerX = mmToWorld(item.centerMm.xMm) - halfWidth;
  const centerZ = mmToWorld(item.centerMm.yMm) - halfDepth;
  const rotationY = ((item.rotationDeg ?? 0) * Math.PI) / 180;
  const cosY = Math.abs(Math.cos(rotationY));
  const sinY = Math.abs(Math.sin(rotationY));
  const extentX = width / 2 * cosY + depth / 2 * sinY;
  const extentZ = width / 2 * sinY + depth / 2 * cosY;

  return {
    minX: centerX - extentX,
    maxX: centerX + extentX,
    minZ: centerZ - extentZ,
    maxZ: centerZ + extentZ,
    topY: height,
  };
}

export function computePlanner3DSceneMetrics(sceneDocument: Planner3DSceneDocument): SceneMetrics {
  const { room, items } = sceneDocument;
  const roomHalfWidthWorld = mmToWorld(room.widthMm) / 2;
  const roomHalfDepthWorld = mmToWorld(room.depthMm) / 2;
  const roomHeightWorld = mmToWorld(room.wallHeightMm);

  let minX = -roomHalfWidthWorld;
  let maxX = roomHalfWidthWorld;
  let minZ = -roomHalfDepthWorld;
  let maxZ = roomHalfDepthWorld;
  let topY = roomHeightWorld;

  for (const item of items) {
    const bounds = getItemBounds(room, item);
    minX = Math.min(minX, bounds.minX);
    maxX = Math.max(maxX, bounds.maxX);
    minZ = Math.min(minZ, bounds.minZ);
    maxZ = Math.max(maxZ, bounds.maxZ);
    topY = Math.max(topY, bounds.topY);
  }

  const centerX = (minX + maxX) / 2;
  const centerZ = (minZ + maxZ) / 2;
  const maxSpanWorld = Math.max(maxX - minX, maxZ - minZ, roomHeightWorld * 1.1, 2.4);
  const targetY = clamp(Math.max(roomHeightWorld * 0.42, topY * 0.48), 0.9, Math.max(roomHeightWorld * 0.72, 1.4));
  const walkEyeHeight = clamp(mmToWorld(room.wallHeightMm * 0.56), 1.55, Math.max(1.7, roomHeightWorld - 0.45));
  const walkMargin = Math.min(
    Math.max(mmToWorld(room.wallThicknessMm) + 0.15, 0.28),
    Math.min(roomHalfWidthWorld, roomHalfDepthWorld) * 0.8,
  );

  return {
    target: [centerX, targetY, centerZ],
    defaultOrbitPosition: [
      centerX + maxSpanWorld * 0.92,
      targetY + maxSpanWorld * 0.44,
      centerZ + maxSpanWorld * 0.96,
    ],
    defaultWalkPosition: [
      clamp(centerX - roomHalfWidthWorld * 0.35, -roomHalfWidthWorld + walkMargin, roomHalfWidthWorld - walkMargin),
      walkEyeHeight,
      clamp(centerZ + roomHalfDepthWorld * 0.2, -roomHalfDepthWorld + walkMargin, roomHalfDepthWorld - walkMargin),
    ],
    walkEyeHeight,
    roomHalfWidthWorld,
    roomHalfDepthWorld,
    roomHeightWorld,
    maxSpanWorld,
    cameraFar: Math.max(120, maxSpanWorld * 8),
    fogNear: Math.max(8, maxSpanWorld * 0.8),
    fogFar: Math.max(28, maxSpanWorld * 4.2),
    shadowScale: maxSpanWorld * 1.15,
    shadowFar: Math.max(12, maxSpanWorld * 1.8),
    orbitMinDistance: Math.max(3.2, maxSpanWorld * 0.36),
    orbitMaxDistance: Math.max(12, maxSpanWorld * 2.8),
    labelPosition: [minX + 0.2, roomHeightWorld + 0.16, minZ + 0.2],
  };
}

function PlannerRoomShell({ room }: { room: Planner3DSceneDocument["room"] }) {
  const halfWidth = mmToWorld(room.widthMm) / 2;
  const halfDepth = mmToWorld(room.depthMm) / 2;
  const wallHeight = mmToWorld(room.wallHeightMm);
  const wallThickness = mmToWorld(room.wallThicknessMm);
  const floorThickness = mmToWorld(room.floorThicknessMm);
  // Front wall is cut to 40% height so the orbit camera can see inside
  const frontWallHeight = wallHeight * 0.4;

  return (
    <group>
      {/* Floor */}
      <mesh receiveShadow position={[0, -floorThickness / 2, 0]}>
        <boxGeometry args={[mmToWorld(room.widthMm), floorThickness, mmToWorld(room.depthMm)]} />
        <meshStandardMaterial color={FOCSS_3D_COLORS.darkMidnightBlue700} roughness={0.98} metalness={0.02} />
      </mesh>
      {/* Back wall — full height */}
      <mesh receiveShadow position={[0, wallHeight / 2, -halfDepth - wallThickness / 2]}>
        <boxGeometry args={[mmToWorld(room.widthMm) + wallThickness * 2, wallHeight, wallThickness]} />
        <meshStandardMaterial color={FOCSS_3D_COLORS.darkMidnightBlue600} roughness={0.82} metalness={0.03} />
      </mesh>
      {/* Front wall — short + translucent for visibility */}
      <mesh receiveShadow position={[0, frontWallHeight / 2, halfDepth + wallThickness / 2]}>
        <boxGeometry args={[mmToWorld(room.widthMm) + wallThickness * 2, frontWallHeight, wallThickness]} />
        <meshStandardMaterial color={FOCSS_3D_COLORS.darkMidnightBlue700} roughness={0.82} metalness={0.03} transparent opacity={0.45} />
      </mesh>
      {/* Left wall — slight transparency */}
      <mesh receiveShadow position={[-halfWidth - wallThickness / 2, wallHeight / 2, 0]}>
        <boxGeometry args={[wallThickness, wallHeight, mmToWorld(room.depthMm)]} />
        <meshStandardMaterial color={FOCSS_3D_COLORS.darkMidnightBlue600} roughness={0.82} metalness={0.03} transparent opacity={0.72} />
      </mesh>
      {/* Right wall — slight transparency */}
      <mesh receiveShadow position={[halfWidth + wallThickness / 2, wallHeight / 2, 0]}>
        <boxGeometry args={[wallThickness, wallHeight, mmToWorld(room.depthMm)]} />
        <meshStandardMaterial color={FOCSS_3D_COLORS.darkMidnightBlue600} roughness={0.82} metalness={0.03} transparent opacity={0.72} />
      </mesh>
      <gridHelper
        args={[Math.max(mmToWorld(room.widthMm), mmToWorld(room.depthMm)) + 2, 16, FOCSS_3D_COLORS.bronze800, FOCSS_3D_COLORS.darkMidnightBlue700]}
        position={[0, 0.001, 0]}
      />
    </group>
  );
}

function PlannerItemMesh({ room, item }: { room: Planner3DSceneDocument["room"]; item: Planner3DItem }) {
  const halfWidth = mmToWorld(room.widthMm) / 2;
  const halfDepth = mmToWorld(room.depthMm) / 2;
  const width = mmToWorld(item.sizeMm.widthMm);
  const depth = mmToWorld(item.sizeMm.depthMm);
  const height = mmToWorld(item.sizeMm.heightMm);
  const x = mmToWorld(item.centerMm.xMm) - halfWidth;
  const z = mmToWorld(item.centerMm.yMm) - halfDepth;
  const y = height / 2;
  const rotationY = ((item.rotationDeg ?? 0) * Math.PI) / 180;

  return (
    <group position={[x, y, z]} rotation={[0, rotationY, 0]}>
      <mesh castShadow receiveShadow>
        <boxGeometry args={[width, height, depth]} />
        <meshStandardMaterial color={resolveItemColor(item)} roughness={0.72} metalness={0.08} />
      </mesh>
      <mesh castShadow receiveShadow position={[0, height / 2 - 0.01, 0]}>
        <boxGeometry args={[width * 0.92, Math.min(mmToWorld(18), height * 0.18), depth * 0.92]} />
        <meshStandardMaterial color={FOCSS_3D_COLORS.white400} roughness={0.34} metalness={0.06} />
      </mesh>
      <Html center transform distanceFactor={10} position={[0, height / 2 + 0.14, 0]} style={{ pointerEvents: "none" }}>
        <div className="planner-viewer-chip min-w-[7rem] rounded-full px-3 py-1 text-center typ-caption font-semibold uppercase tracking-[0.16em] text-body">
          {item.name}
        </div>
      </Html>
    </group>
  );
}

function OrbitCamera({
  cameraMemoryRef,
  metrics,
}: {
  cameraMemoryRef: React.MutableRefObject<CameraMemory>;
  metrics: SceneMetrics;
}) {
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const controlsRef = useRef<OrbitControlsImpl | null>(null);

  useEffect(() => {
    const camera = cameraRef.current;
    const controls = controlsRef.current;
    if (!camera || !controls) return;

    const savedPose = cameraMemoryRef.current.orbit;
    const position = savedPose?.position ?? metrics.defaultOrbitPosition;
    const target = savedPose?.target ?? metrics.target;

    camera.position.set(position[0], position[1], position[2]);
    controls.target.set(target[0], target[1], target[2]);
    controls.update();
  }, [cameraMemoryRef, metrics]);

  const handleControlsChange = () => {
    const camera = cameraRef.current;
    const controls = controlsRef.current;
    if (!camera || !controls) return;

    cameraMemoryRef.current.orbit = {
      position: [camera.position.x, camera.position.y, camera.position.z],
      target: [controls.target.x, controls.target.y, controls.target.z],
    };
  };

  return (
    <>
      <PerspectiveCamera ref={cameraRef} makeDefault fov={42} near={0.1} far={metrics.cameraFar} />
      <OrbitControls
        ref={controlsRef}
        makeDefault
        enableDamping
        dampingFactor={0.08}
        minDistance={metrics.orbitMinDistance}
        maxDistance={metrics.orbitMaxDistance}
        maxPolarAngle={Math.PI / 2.03}
        target={metrics.target}
        onChange={handleControlsChange}
      />
    </>
  );
}

function WalkCamera({
  cameraMemoryRef,
  metrics,
  room,
}: {
  cameraMemoryRef: React.MutableRefObject<CameraMemory>;
  metrics: SceneMetrics;
  room: Planner3DSceneDocument["room"];
}) {
  const gl = useThree((state) => state.gl);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
  const moveSpeed = Math.min(0.11, Math.max(0.035, metrics.maxSpanWorld * 0.018));
  const lookSpeed = 0.002;
  const keys = useRef<Set<string>>(new Set());
  const euler = useRef(new THREE.Euler(0, 0, 0, "YXZ"));
  const isPointerLocked = useRef(false);

  const persistWalkPose = useCallback(() => {
    const camera = cameraRef.current;
    if (!camera) return;

    cameraMemoryRef.current.walk = {
      position: [camera.position.x, camera.position.y, camera.position.z],
      rotation: [euler.current.x, euler.current.y],
    };
  }, [cameraMemoryRef]);

  useEffect(() => {
    const camera = cameraRef.current;
    if (!camera) return;

    const savedPose = cameraMemoryRef.current.walk;
    if (savedPose) {
      camera.position.set(savedPose.position[0], savedPose.position[1], savedPose.position[2]);
      euler.current.set(savedPose.rotation[0], savedPose.rotation[1], 0, "YXZ");
      camera.quaternion.setFromEuler(euler.current);
    } else {
      camera.position.set(
        metrics.defaultWalkPosition[0],
        metrics.defaultWalkPosition[1],
        metrics.defaultWalkPosition[2],
      );
      camera.lookAt(metrics.target[0], metrics.walkEyeHeight, metrics.target[2]);
      euler.current.setFromQuaternion(camera.quaternion, "YXZ");
    }

    persistWalkPose();

    const handleKeyDown = (event: KeyboardEvent) => keys.current.add(event.key.toLowerCase());
    const handleKeyUp = (event: KeyboardEvent) => keys.current.delete(event.key.toLowerCase());
    const handleMouseMove = (event: MouseEvent) => {
      if (!isPointerLocked.current) return;
      euler.current.y -= event.movementX * lookSpeed;
      euler.current.x -= event.movementY * lookSpeed;
      euler.current.x = Math.max(-Math.PI / 2.5, Math.min(Math.PI / 2.5, euler.current.x));
    };
    const handlePointerLockChange = () => {
      isPointerLocked.current = document.pointerLockElement === gl.domElement;
    };
    const handleCanvasClick = () => {
      if (!isPointerLocked.current) {
        void gl.domElement.requestPointerLock();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    window.addEventListener("keyup", handleKeyUp);
    window.addEventListener("mousemove", handleMouseMove);
    document.addEventListener("pointerlockchange", handlePointerLockChange);
    gl.domElement.addEventListener("click", handleCanvasClick);

    return () => {
      persistWalkPose();
      window.removeEventListener("keydown", handleKeyDown);
      window.removeEventListener("keyup", handleKeyUp);
      window.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("pointerlockchange", handlePointerLockChange);
      gl.domElement.removeEventListener("click", handleCanvasClick);
      if (document.pointerLockElement === gl.domElement) {
        void document.exitPointerLock();
      }
    };
  }, [cameraMemoryRef, gl, metrics, persistWalkPose]);

  useFrame((_state, delta) => {
    const camera = cameraRef.current;
    if (!camera) return;

    camera.quaternion.setFromEuler(euler.current);

    const direction = new THREE.Vector3();
    const forward = new THREE.Vector3();
    const right = new THREE.Vector3();
    camera.getWorldDirection(forward);
    forward.y = 0;

    if (forward.lengthSq() > 0) {
      forward.normalize();
    }

    right.crossVectors(forward, UP_VECTOR);
    if (right.lengthSq() > 0) {
      right.normalize();
    }

    if (keys.current.has("w") || keys.current.has("arrowup")) direction.add(forward);
    if (keys.current.has("s") || keys.current.has("arrowdown")) direction.sub(forward);
    if (keys.current.has("a") || keys.current.has("arrowleft")) direction.sub(right);
    if (keys.current.has("d") || keys.current.has("arrowright")) direction.add(right);

    if (direction.lengthSq() > 0) {
      camera.position.add(direction.normalize().multiplyScalar(moveSpeed * Math.min(delta * 60, 1.8)));
    }

    const walkMargin = Math.min(
      Math.max(mmToWorld(room.wallThicknessMm) + 0.15, 0.28),
      Math.min(metrics.roomHalfWidthWorld, metrics.roomHalfDepthWorld) * 0.8,
    );

    camera.position.set(
      clamp(
        camera.position.x,
        -metrics.roomHalfWidthWorld + walkMargin,
        metrics.roomHalfWidthWorld - walkMargin,
      ),
      metrics.walkEyeHeight,
      clamp(
        camera.position.z,
        -metrics.roomHalfDepthWorld + walkMargin,
        metrics.roomHalfDepthWorld - walkMargin,
      ),
    );

    persistWalkPose();
  });

  return <PerspectiveCamera ref={cameraRef} makeDefault fov={70} near={0.1} far={metrics.cameraFar} />;
}

function Planner3DRenderEvidence({
  viewerRef,
}: {
  viewerRef: React.RefObject<HTMLDivElement | null>;
}) {
  const { gl } = useThree();
  const reported = useRef(false);

  useEffect(() => {
    return addAfterEffect(() => {
      if (reported.current) return;

      const context = gl.getContext();
      const width = context.drawingBufferWidth;
      const height = context.drawingBufferHeight;
      if (width <= 0 || height <= 0) return;

      const pixels = new Uint8Array(4);
      context.readPixels(
        Math.max(0, Math.floor(width / 2)),
        Math.max(0, Math.floor(height / 2)),
        1,
        1,
        context.RGBA,
        context.UNSIGNED_BYTE,
        pixels,
      );

      if (!pixels.some((value) => value > 0)) return;

      viewerRef.current?.setAttribute("data-render-evidence", "ready");
      viewerRef.current?.setAttribute(
        "data-render-luma",
        String(pixels[0] + pixels[1] + pixels[2] + pixels[3]),
      );
      reported.current = true;
    });
  }, [gl, viewerRef]);

  return null;
}

function PlannerScene({
  cameraMemoryRef,
  cameraMode,
  sceneDocument,
  viewerRef,
}: {
  cameraMemoryRef: React.MutableRefObject<CameraMemory>;
  cameraMode: ViewerCameraMode;
  sceneDocument: Planner3DSceneDocument;
  viewerRef: React.RefObject<HTMLDivElement | null>;
}) {
  const { room, items } = sceneDocument;
  const metrics = useMemo(() => computePlanner3DSceneMetrics(sceneDocument), [sceneDocument]);

  return (
    <>
      <Planner3DRenderEvidence viewerRef={viewerRef} />
      <color attach="background" args={[FOCSS_3D_COLORS.darkMidnightBlue950]} />
      <fog attach="fog" args={[FOCSS_3D_COLORS.darkMidnightBlue950, metrics.fogNear, metrics.fogFar]} />
      <ambientLight intensity={0.92} />
      <hemisphereLight intensity={0.58} groundColor={FOCSS_3D_COLORS.darkMidnightBlue800} color={FOCSS_3D_COLORS.oceanBoatBlue100} />
      <directionalLight
        position={[6, 12, 9]}
        intensity={1.65}
        castShadow
        shadow-mapSize-width={2048}
        shadow-mapSize-height={2048}
        shadow-camera-near={0.5}
        shadow-camera-far={metrics.shadowFar}
      />
      <spotLight position={[-8, 10, -5]} angle={0.34} penumbra={0.7} intensity={0.9} color={FOCSS_3D_COLORS.white350} />

      {cameraMode === "orbit" ? (
        <OrbitCamera cameraMemoryRef={cameraMemoryRef} metrics={metrics} />
      ) : (
        <WalkCamera cameraMemoryRef={cameraMemoryRef} metrics={metrics} room={room} />
      )}
      <PlannerRoomShell room={room} />
      {items.map((item) => (
        <PlannerItemMesh key={item.id} room={room} item={item} />
      ))}
      <ContactShadows
        position={[0, 0.005, 0]}
        opacity={items.length > 0 ? 0.42 : 0.24}
        scale={metrics.shadowScale}
        blur={2.6}
        far={metrics.shadowFar}
      />
      <Html position={metrics.labelPosition} style={{ pointerEvents: "none" }}>
        <div className="planner-viewer-surface rounded-2xl border border-theme-soft px-3 py-2 typ-caption font-semibold uppercase tracking-[0.18em] text-body">
          mm scene
        </div>
      </Html>
    </>
  );
}

class ThreeCanvasErrorBoundary extends Component<{ children: ReactNode; fallback?: ReactNode }, { hasError: boolean }> {
  state = { hasError: false };
  static getDerivedStateFromError() {
    return { hasError: true };
  }
  componentDidCatch(error: any, errorInfo: ErrorInfo) {
    void logClientError({
      error,
      label: "Planner3DViewer-canvas",
      componentStack: errorInfo?.componentStack ?? "",
    });
  }
  render() {
    if (this.state.hasError) {
      return (
        this.props.fallback || (
          <div className="surface-inverse flex h-full min-h-[420px] items-center justify-center px-6">
            <div className="planner-viewer-surface max-w-md rounded-[1.35rem] border border-warning px-5 py-4 text-center">
              <div className="typ-caption font-semibold uppercase tracking-[0.16em] text-warning">WebGL render crash</div>
              <div className="mt-2 typ-caption-lg text-body">
                An unexpected error occurred during 3D rendering. You can continue editing in 2D or reload to retry.
              </div>
            </div>
          </div>
        )
      );
    }
    return this.props.children;
  }
}

export function Planner3DViewer({ document, className }: Planner3DViewerProps) {
  const [cameraMode, setCameraMode] = useState<ViewerCameraMode>("orbit");
  const [webglProbe] = useState<WebGLProbeResult>(() => probeWebGL());
  const viewerRef = useRef<HTMLDivElement>(null);
  const sceneDocument = useMemo(() => buildPlanner3DSceneDocument(document), [document]);
  const sceneSignature = useMemo(() => getSceneSignature(sceneDocument), [sceneDocument]);
  const cameraMemoryRef = useRef<CameraMemory>({ sceneSignature });

  useEffect(() => {
    cameraMemoryRef.current = { sceneSignature };
  }, [sceneSignature]);

  useEffect(() => {
    viewerRef.current?.removeAttribute("data-render-evidence");
    viewerRef.current?.removeAttribute("data-render-luma");
  }, [sceneSignature, webglProbe.ok]);

  // BUG-02 fix: capture renderer via onCreated so cleanup does not rely on
  // a stale DOM query that may already be torn down by React on unmount.
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);

  useEffect(() => {
    return () => {
      rendererRef.current?.dispose();
      rendererRef.current = null;
    };
  }, []);

  return (
    <div
      ref={viewerRef}
      className={`pw-viewer-canvas surface-inverse relative h-full min-h-0 w-full overflow-hidden rounded-[2rem] border border-theme-soft shadow-theme-float ${className ?? ""}`}
      data-testid="planner-3d-viewer"
      data-webgl-status={webglProbe.ok ? "ready" : "fallback"}
    >
      {webglProbe.ok ? (
        <Suspense
          fallback={
            <div className="surface-inverse flex h-full min-h-[420px] items-center justify-center">
              <div className="planner-viewer-chip rounded-full px-4 py-2 typ-caption font-semibold uppercase tracking-[0.22em] text-body">
                Preparing 3D scene
              </div>
            </div>
          }
        >
          <ThreeCanvasErrorBoundary>
            <Canvas
              shadows="basic"
              dpr={[1, 1.75]}
              gl={{
                antialias: true,
                alpha: false,
                powerPreference: "high-performance",
                preserveDrawingBuffer: true,
              }}
              className="h-full min-h-0 w-full"
              data-testid="planner-3d-canvas"
              onCreated={({ gl }) => {
                // BUG-02: capture renderer so dispose() is called on the right instance.
                rendererRef.current = gl;
              }}
            >
              <PlannerScene
                cameraMemoryRef={cameraMemoryRef}
                cameraMode={cameraMode}
                sceneDocument={sceneDocument}
                viewerRef={viewerRef}
              />
            </Canvas>
          </ThreeCanvasErrorBoundary>
        </Suspense>
      ) : (
        <div
          className="surface-inverse flex h-full min-h-[420px] items-center justify-center px-6"
          data-testid="planner-3d-fallback"
        >
          <div className="planner-viewer-surface max-w-md rounded-[1.35rem] border border-warning px-5 py-4 text-center">
            <div className="typ-caption font-semibold uppercase tracking-[0.16em] text-warning">3D unavailable</div>
            <div className="mt-2 typ-caption-lg text-body">
              WebGL is unavailable in this browser context. Continue editing in 2D or Split while the room data stays intact.
            </div>
          </div>
        </div>
      )}

      <div className="pointer-events-none absolute inset-x-0 bottom-0 h-32 bg-gradient-to-t from-[color:var(--surface-inverse)] to-transparent" />

      <div className="absolute bottom-4 right-4 z-20 flex gap-2">
        <button
          type="button"
          aria-pressed={cameraMode === "orbit"}
          onClick={() => setCameraMode("orbit")}
          className={`planner-viewer-chip flex items-center gap-2 rounded-full px-4 py-2 typ-caption font-semibold uppercase tracking-[0.18em] transition ${cameraMode === "orbit" ? "planner-viewer-chip-active" : "hover:border-[color:var(--planner-border-hover)] hover:text-strong"}`}
        >
          <Eye className="h-4 w-4" /> Orbit
        </button>
        <button
          type="button"
          aria-pressed={cameraMode === "walk"}
          onClick={() => setCameraMode("walk")}
          className={`planner-viewer-chip flex items-center gap-2 rounded-full px-4 py-2 typ-caption font-semibold uppercase tracking-[0.18em] transition ${cameraMode === "walk" ? "planner-viewer-chip-active" : "hover:border-[color:var(--planner-border-hover)] hover:text-strong"}`}
        >
          <User className="h-4 w-4" /> Walk
        </button>
      </div>

      <div className="absolute left-4 top-4 z-20 flex max-w-[20rem] flex-col gap-2">
        <div className="planner-viewer-surface rounded-[1.35rem] border border-theme-soft px-4 py-3">
          <div className="typ-caption font-semibold uppercase tracking-[0.18em] text-muted">
            {cameraMode === "orbit" ? "Orbit camera" : "Walk camera"}
          </div>
          <div className="mt-1 typ-caption-lg text-body">
            {cameraMode === "orbit"
              ? "Drag to inspect the document-mapped room and product shells."
              : "Click into the canvas, then use WASD or arrow keys with mouse look."}
          </div>
        </div>
        <div className="planner-viewer-surface rounded-[1.35rem] border border-theme-soft px-4 py-3">
          <div className="typ-caption font-semibold uppercase tracking-[0.16em] text-muted">Renderer</div>
          <div className="mt-1 typ-caption-lg text-body" data-testid="planner-3d-renderer">
            {webglProbe.ok
              ? `${webglProbe.context?.toUpperCase() ?? "WEBGL"} · ${webglProbe.renderer ?? "Renderer unavailable"}`
              : "Fallback mode"}
          </div>
        </div>
        {sceneDocument.items.length === 0 ? (
          <div className="planner-viewer-surface rounded-[1.35rem] border border-warning px-4 py-3">
            <div className="typ-caption font-semibold uppercase tracking-[0.16em] text-warning">Empty mapped scene</div>
            <div className="mt-1 typ-caption-lg text-body">
              No planner items are mapped yet. The room shell is using the document dimensions.
            </div>
          </div>
        ) : null}
        {cameraMode === "walk" ? (
          <div className="planner-viewer-surface rounded-[1.35rem] border border-theme-soft px-4 py-3">
            <div className="typ-caption font-semibold uppercase tracking-[0.16em] text-muted">Controls</div>
            <div className="mt-1 typ-caption-lg text-body">WASD or arrow keys | Mouse look | Esc releases pointer lock</div>
          </div>
        ) : null}
      </div>
    </div>
  );
}

/**
 * floorplanCanvas.ts — Fabric canvas API factory.
 *
 * Types and pure utilities live in floorplanCanvasTypes.ts (split for file-size).
 */
import {
  Canvas as FabricCanvas,
  Group,
  Point,
  ActiveSelection,
  FabricText,
  Pattern,
  loadSVGFromString,
  util as fabricUtil,
} from 'fabric';
import type { Rect, FabricObject, Line } from 'fabric';
import { saveAs as saveFile } from 'file-saver';
import { formatDate } from '../lib/formatDate';
import * as _ from '../lib/helpers';
import type { FloorplanCanvasApi, InsertPayload } from '../context/FloorplanContext';
import type { FabricContextMenuState, FabricDrawTool } from '../fabricDrawToolTypes';
import { DEFAULT_FABRIC_DRAW_COLOR, DEFAULT_FABRIC_FILL_COLOR } from '../fabricDrawToolTypes';
import { applyFabricTransformLocks, canEditFabricFill } from '../fabricObjectUtils';
import { wireFabricDrawTools } from './fabricDrawTools';


// Types and pure utilities are in floorplanCanvasTypes.ts
export {
  type PlannerFabricObject,
  type InsertPayloadObj,
  type FloorplanCtx,
  resolveLayerCategory,
  getBoundingRect,
} from './floorplanCanvasTypes';

import type {
  PlannerFabricObject,
  InsertPayloadObj,
  FloorplanCtx,
} from './floorplanCanvasTypes';
import { getBoundingRect, resolveLayerCategory } from './floorplanCanvasTypes';

export function createFloorplanCanvasApi(
  ctxRef: { current: FloorplanCtx },
  canvasEl: HTMLCanvasElement,
): FloorplanCanvasApi & {
  init: () => void;
  onKeyDown: (e: KeyboardEvent) => void;
  onKeyUp: (e: KeyboardEvent) => void;
  dispose: () => void;
} {
  let view!: FabricCanvas;
  let corners: Rect[] = [];
  const walls: Line[] = [];
  let lastObjectDefinition: InsertPayloadObj | null = null;
  let lastObject: PlannerFabricObject | null = null;
  let copied: PlannerFabricObject | null = null;
  let selections: FabricObject[] = [];
  let CTRL_KEY_DOWN = false;
  const ROOM_SIZE = { width: 960, height: 480 };
  let DEFAULT_CHAIR: Record<string, unknown> | null = null;
  let REMOVE_DW = false;
  let gridPattern: Pattern | null = null;
  let drawTool: FabricDrawTool = 'select';
  let drawColor: string = DEFAULT_FABRIC_DRAW_COLOR;
  let drawFillColor: string = DEFAULT_FABRIC_FILL_COLOR;
  let contextMenuListener: ((state: FabricContextMenuState | null) => void) | null = null;
  let drawToolsController: ReturnType<typeof wireFabricDrawTools> | null = null;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const wc: any = null;

  const {
    RL_VIEW_WIDTH,
    RL_VIEW_HEIGHT,
    RL_FOOT,
    RL_AISLEGAP,
    RL_ROOM_OUTER_SPACING,
    RL_ROOM_INNER_SPACING,
    RL_UNGROUPABLES,
    RL_CREDIT_TEXT,
    RL_CREDIT_TEXT_PARAMS
  } = _;

  // ─── convenience aliases that delegate to wc (available after setCanvasView) ─

  function isWallOrCorner(_obj: unknown): boolean {
    return false;
  }



  /** Scene coordinates (zoom-aware). Never use legacy e.pointer — it can be viewport space in Fabric v7. */
  function getScenePointer(e: unknown): Point | null {
    if (!view) return null;
    const native = (e as Record<string, unknown>)?.e;
    if (native) {
      try {
        view.calcOffset();
        return view.getScenePoint(native as MouseEvent | TouchEvent);
      } catch {
        /* fall through */
      }
    }
    const scene = (e as Record<string, unknown>)?.scenePoint;
    if (scene && typeof (scene as Point).x === 'number' && typeof (scene as Point).y === 'number') {
      return scene instanceof Point ? scene : new Point((scene as Point).x, (scene as Point).y);
    }
    return null;
  }

  function init() {
    DEFAULT_CHAIR = ctxRef.current.defaultChair as Record<string, unknown> | null;
    setCanvasView();
    syncGrid();
    wc?.setRoom(ROOM_SIZE);
    saveState();
  }

  function roomOrigin() {
    return RL_ROOM_OUTER_SPACING + RL_ROOM_INNER_SPACING;
  }

  function onKeyDown(event: KeyboardEvent) {
    const code = event.key || event.keyCode;
    // Ctrl Key is down
    if (event.ctrlKey) {
      CTRL_KEY_DOWN = true;
      // Ctrl + Shift + Z
      if (event.shiftKey && code === 90)
        redo();
      else if (code === 90)
        undo();
      else if (code === 67)
        copy();
      else if (code === 86)
        paste();
      else if (code === 37)
        rotate();
      else if (code === 39)
        rotate(false);
      else if (code === 71)
        group();
    }
    else if (code === 46)
      deleteOp();
    else if (code === 37)
      move('LEFT');
    else if (code === 38)
      move('UP');
    else if (code === 39)
      move('RIGHT');
    else if (code === 40)
      move('DOWN');
    else if (code === 'Escape' && ctxRef.current.roomEdit) {
      event.preventDefault();
      ctxRef.current.exitRoomEdit();
    }
  }

  function onKeyUp(event: KeyboardEvent) {
    if (event.key === 'Control') {
      CTRL_KEY_DOWN = false;
    }
  }

  function setGroupableState() {
    if (selections.length > 1) {
      ctxRef.current.setUngroupable(false);
      return;
    }

    const obj = view.getActiveObject() as PlannerFabricObject | undefined;
    if (!obj) return;
    const type = obj.name ? obj.name.split(':')[0] : '';

    if (RL_UNGROUPABLES.indexOf(type) > -1) {
      ctxRef.current.setUngroupable(false);
    } else {
      ctxRef.current.setUngroupable(true);
    }
  }

  function onSelected() {
    const active = view.getActiveObject();
    if (!active) return;

    const objects = view.getActiveObjects();
    objects.forEach((obj) => applyFabricTransformLocks(obj));

    if (active instanceof ActiveSelection) {
      const allResizable = objects.length > 0 && objects.every((obj) => {
        applyFabricTransformLocks(obj);
        return !obj.lockScalingX;
      });
      active.lockScalingX = !allResizable;
      active.lockScalingY = !allResizable;
      active.lockRotation = !allResizable;
    } else {
      applyFabricTransformLocks(active);
      if (!(active as PlannerFabricObject).name) {
        (active as PlannerFabricObject).name = 'GROUP';
      }
    }

    selections = objects;
    ctxRef.current.setSelections(selections);
    setGroupableState();
  }

  function handleSelectionChange() {
    const active = view.getActiveObject();
    if (isWallOrCorner(active)) {
      selections = [active as FabricObject];
      ctxRef.current.setSelections(selections);
      ctxRef.current.setUngroupable(false);
      return;
    }
    onSelected();
  }

  /**********************************************************************************************************
   * init the canvas view & bind events
   * -------------------------------------------------------------------------------------------------------
   */
  function setCanvasView() {
    const canvas = new FabricCanvas(canvasEl, {
      targetFindTolerance: 12,
      selection: true,
    });
    canvas.setDimensions({
      width: RL_VIEW_WIDTH * RL_FOOT,
      height: RL_VIEW_HEIGHT * RL_FOOT,
    });
    view = canvas;
    syncGrid();
    view.calcOffset();

    // Initialize walls controller — must come before any event wiring


    view.on('selection:created', () => {
      handleSelectionChange();
    });

    view.on('selection:updated', () => {
      handleSelectionChange();
    });

    view.on('selection:cleared', (_e: unknown) => {
      selections = []; ctxRef.current.setSelections(selections);
      ctxRef.current.setUngroupable(false);
    });

    view.on('object:modified', (e) => {
      if (e.action === 'drag') {
        wc?.handleObjectMoved();
      }
      saveState();
    });

    view.on('contextmenu', (e: unknown) => {
      const ev = e as Record<string, unknown>;
      const native = ev.e as MouseEvent | undefined;
      native?.preventDefault?.();
      native?.stopPropagation?.();
      if (!native || !contextMenuListener) return;
      const target = (ev.target as FabricObject | undefined) ?? null;
      if (target) {
        if (isWallOrCorner(target)) {
          view.setActiveObject(target);
          selections = [target];
          ctxRef.current.setSelections(selections);
          ctxRef.current.setUngroupable(false);
        } else {
          view.setActiveObject(target);
          onSelected();
        }
        view.requestRenderAll();
      }
      contextMenuListener({
        clientX: native.clientX,
        clientY: native.clientY,
        target: target as Record<string, unknown> | null,
      });
    });

    view.on('mouse:down:before', (e: unknown) => {
      wc?.handleMouseDownBefore(e);
    });

    view.on('object:moving', (e: unknown) => {
      const obj = (e as Record<string, unknown>).target;
      // Wall/corner moving — delegate entirely to wc
      wc?.handleObjectMoving(e);

      // Grid snapping
      const target = obj as FabricObject;
      if (ctxRef.current.snapEnabled && target && !isWallOrCorner(target)) {
        const snap = RL_FOOT;
        if (target.left !== undefined) {
          target.left = Math.round(target.left / snap) * snap;
        }
        if (target.top !== undefined) {
          target.top = Math.round(target.top / snap) * snap;
        }
      }

      // Door/window snapping to nearest wall
      const point = getScenePointer(e);
      if (!point) return;

      if (obj && isDW(obj) && obj instanceof Group) {
        let wall: Line | undefined;
        let distance = 999;
        const dist2 = (v: Point, w: Point) => (v.x - w.x) * (v.x - w.x) + (v.y - w.y) * (v.y - w.y);
        const distToSegmentSquared = (p: Point, v: Point, w: Point) => {
          const l2 = dist2(v, w);

          if (l2 === 0)
            return dist2(p, v);

          const t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;

          if (t < 0)
            return dist2(p, v);

          if (t > 1)
            return dist2(p, w);

          return dist2(p, new Point(v.x + t * (w.x - v.x), v.y + t * (w.y - v.y)));
        };
        const point_to_line = (p: Point, v: Point, w: Point) => Math.sqrt(distToSegmentSquared(p, v, w));

        walls.forEach(w => {
          const d = point_to_line(point, new Point(w.x1 ?? 0, w.y1 ?? 0), new Point(w.x2 ?? 0, w.y2 ?? 0));
          if (d < distance) {
            distance = d;
            wall = w;
          }
        });

        if (distance > 20 || !wall) {
          REMOVE_DW = true;
        } else {
          REMOVE_DW = false;
        }
      }
    });

    view.on('mouse:up', (e: unknown) => {
      const obj = (e as Record<string, unknown>).target as PlannerFabricObject | undefined;
      wc?.handleMouseUp(e);

      if (REMOVE_DW && obj) {
        view.remove(obj);
        REMOVE_DW = false;
      }
    });

    view.on('mouse:dblclick', (e: unknown) => {
      wc?.handleDoubleClick(e);
    });

    drawToolsController = wireFabricDrawTools({
      getView: () => view,
      getScenePointer,
      getDrawTool: () => drawTool,
      getDrawColor: () => drawColor,
      getDrawFillColor: () => drawFillColor,
      roomEditActive: () => false,
      saveState,
    });

    view.on('mouse:wheel', (event: unknown) => {
      const native = (event as Record<string, unknown>).e;
      if (!(native instanceof WheelEvent)) return;
      zoomToPointer(native);
    });
  }


  /**********************************************************************************************************/

  function editRoom() {
    // No-op: fabricWalls is removed
  }

  function cancelRoomEdition() {
    drawToolsController?.applyCanvasMode();
    wc?.refreshRoomEditObjectModes(false);
    selections = [];
    ctxRef.current.setSelections(selections);
    ctxRef.current.setUngroupable(false);
    view.discardActiveObject();
  }

  async function handleObjectInsertion({ type, object }: InsertPayload) {
    const payloadObj = object as InsertPayloadObj;

    if (type === 'ROOM') {
      wc?.setRoom(payloadObj as { width: number; height: number });
      saveState();
      return;
    }

    if (type === 'WALL') {
      const { x1, y1, x2, y2, name } = payloadObj as { x1: number; y1: number; x2: number; y2: number; name?: string };
      const { Line } = await import('fabric');
      const wall = new Line([x1, y1, x2, y2], {
        stroke: '#1f2937',
        strokeWidth: 2,
        fill: '',
        originX: 'center',
        originY: 'center',
        selectable: true,
        evented: true,
        hasControls: true,
        hasBorders: true,
      });
      wall.set('name', name || `WALL:${Date.now()}`);
      view.add(wall);
      view.setActiveObject(wall);
      saveState();
      return;
    }

    let group = _.createFurniture(type, payloadObj, (DEFAULT_CHAIR ?? undefined) as Record<string, unknown> | undefined);
    if (type === 'GENERIC' && payloadObj.svg) {
      try {
        const parsed = await loadSVGFromString(payloadObj.svg);
        const objects = parsed.objects.filter((obj): obj is FabricObject => Boolean(obj));
        if (objects.length) {
          group = fabricUtil.groupSVGElements(objects, parsed.options);
          group.set({
            name: `GENERIC:${payloadObj.name || payloadObj.title || 'Item'}`,
          });
          group.scaleX = (payloadObj.width ?? 1) / Math.max(1, group.width);
          group.scaleY = (payloadObj.height ?? 1) / Math.max(1, group.height);
        }
      } catch {
        // Keep the generic footprint as a safe fallback for malformed symbols.
      }
    }

    if (payloadObj.id) {
      group.set('id', payloadObj.id);
    }
    if (payloadObj.name && type === 'GENERIC' && payloadObj.variant !== 'zone' && payloadObj.variant !== 'room') {
      group.set('name', `GENERIC:${payloadObj.name}`);
    }



    // retrieve spacing from object, use rlAisleGap if not specified
    const newLR = payloadObj.lrSpacing || RL_AISLEGAP;
    const newTB = payloadObj.tbSpacing || RL_AISLEGAP;

    const explicitLeft = typeof payloadObj.left === 'number' ? payloadObj.left : null;
    const explicitTop = typeof payloadObj.top === 'number' ? payloadObj.top : null;
    const hasExplicitPosition = explicitLeft !== null && explicitTop !== null;
    group.left = newLR + (group.width / 2) + roomOrigin();
    group.top = newTB + (group.height / 2) + roomOrigin();

    if (hasExplicitPosition) {
      group.left = explicitLeft + roomOrigin();
      group.top = explicitTop + roomOrigin();
    }

    if (lastObject && !hasExplicitPosition) {
      const lastLR = lastObjectDefinition?.lrSpacing || RL_AISLEGAP;
      const lastTB = lastObjectDefinition?.tbSpacing || RL_AISLEGAP;
      const useLR = Math.max(newLR, lastLR);
      const useTB = Math.max(newTB, lastTB);

      const lastHalfWidth = ((lastObject.width ?? 0) || lastObjectDefinition?.width || 100) / 2;
      const lastHalfHeight = ((lastObject.height ?? 0) || lastObjectDefinition?.height || 40) / 2;

      let newLeft = lastObject.left + lastHalfWidth + useLR + group.width / 2;
      let newTop = lastObject.top - lastHalfHeight + useTB + group.height / 2;

      if (newLeft + group.width / 2 + newLR > ROOM_SIZE.width) {
        newLeft = roomOrigin() + newLR + group.width / 2;
        newTop = lastObject.top + lastHalfHeight + useTB + group.height / 2;
      }

      group.left = Math.max(newLeft, roomOrigin() + newLR + group.width / 2);
      group.top = Math.max(newTop, roomOrigin() + newTB + group.height / 2);
    }

    if (!hasExplicitPosition && view) {
      let attempts = 0;
      const spacing = 40;
      while (attempts < 50) {
        const collision = view.getObjects().some(obj => 
          !(obj as any).name?.includes('WALL') && 
          (obj as any).name !== 'CORNER' &&
          Math.abs((obj.left || 0) - (group.left || 0)) < 5 && 
          Math.abs((obj.top || 0) - (group.top || 0)) < 5
        );
        if (!collision) break;
        group.left += spacing;
        if (group.left + (group.width || 0) / 2 > ROOM_SIZE.width + roomOrigin()) {
          group.left = newLR + ((group.width || 0) / 2) + roomOrigin();
          group.top += spacing;
        }
        attempts++;
      }
    }

    view.add(group);
    view.setActiveObject(group);

    lastObject = group;
    lastObjectDefinition = payloadObj;
    saveState();
  }


  async function restoreFromState(current: string | null) {
    if (!current) return;
    view.clear();
    await view.loadFromJSON(current);
    view.discardActiveObject();
    view.renderAll();
    corners = view.getObjects().filter((obj) => (obj as PlannerFabricObject).name === 'CORNER') as Rect[];
    wc?.drawRoom();
    ctxRef.current.setSelections([]);
    ctxRef.current.setUngroupable(false);
    syncGrid();
    window.requestAnimationFrame(() => {
      const zoomPct = fitToStage();
      ctxRef.current.syncZoom(zoomPct);
      view.calcOffset();
      view.requestRenderAll();
    });
  }

  function createGridPattern() {
    const major = RL_FOOT * 5;
    const minor = RL_FOOT;
    const source = document.createElement('canvas');
    source.width = major;
    source.height = major;
    const g = source.getContext('2d');

    if (!g) {
      return null;
    }

    g.clearRect(0, 0, source.width, source.height);

    g.strokeStyle = 'rgba(15, 37, 56, 0.08)';
    g.lineWidth = 1;

    for (let x = minor; x < source.width; x += minor) {
      g.beginPath();
      g.moveTo(x, 0);
      g.lineTo(x, source.height);
      g.stroke();
    }

    for (let y = minor; y < source.height; y += minor) {
      g.beginPath();
      g.moveTo(0, y);
      g.lineTo(source.width, y);
      g.stroke();
    }

    g.strokeStyle = 'rgba(15, 37, 56, 0.18)';

    g.beginPath();
    g.moveTo(0, 0.5);
    g.lineTo(source.width, 0.5);
    g.stroke();

    g.beginPath();
    g.moveTo(0.5, 0);
    g.lineTo(0.5, source.height);
    g.stroke();

    return new Pattern({
      source,
      repeat: 'repeat',
    });
  }

  function syncGrid() {
    if (!view) return;

    if (!gridPattern) {
      gridPattern = createGridPattern();
    }

    view.backgroundColor = ctxRef.current.gridEnabled && gridPattern ? gridPattern : '#eceff1';
    view.requestRenderAll();
  }

  /** Save current state */
  function saveState() {
    const state = view.toDatalessJSON(['id', 'name', 'hasControls', 'selectable', 'hasBorders', 'evented', 'hoverCursor', 'moveCursor']);
    ctxRef.current.pushState(JSON.stringify(state));
  }

  function exportState() {
    const state = view.toDatalessJSON([
      'id',
      'name',
      'hasControls',
      'selectable',
      'hasBorders',
      'evented',
      'hoverCursor',
      'moveCursor',
    ]);
    return JSON.stringify(state);
  }

  async function importState(serialized: string) {
    await restoreFromState(serialized);
  }


  async function undo() {
    let current: string | null = null;

    if (ctxRef.current.roomEdit) {
      const states = [...ctxRef.current.roomEditStates];
      if (states.length <= 1) return;
      const popped = states.pop() ?? '';
      current = states[states.length - 1];
      ctxRef.current.setRoomEditStates(states);
      ctxRef.current.setRoomEditRedoStates([...ctxRef.current.roomEditRedoStates, popped]);
    } else {
      const states = [...ctxRef.current.states];
      if (states.length <= 1) return;
      const popped = states.pop() ?? '';
      current = states[states.length - 1];
      ctxRef.current.setStates(states);
      ctxRef.current.setRedoStates([...ctxRef.current.redoStates, popped]);
    }

    await restoreFromState(current);
  }


  /** Redo operation */
  async function redo() {
    let current: string | null = null;

    if (ctxRef.current.roomEdit) {
      const redo = [...ctxRef.current.roomEditRedoStates];
      if (!redo.length) return;
      current = redo.pop() ?? '';
      ctxRef.current.setRoomEditRedoStates(redo);
      ctxRef.current.setRoomEditStates([...ctxRef.current.roomEditStates, current]);
    } else {
      const redo = [...ctxRef.current.redoStates];
      if (!redo.length) return;
      current = redo.pop() ?? '';
      ctxRef.current.setRedoStates(redo);
      ctxRef.current.setStates([...ctxRef.current.states, current]);
    }

    await restoreFromState(current);
  }


  /** Copy operation */
  async function copy() {
    if (ctxRef.current.roomEdit) {
      return;
    }
    const active = view.getActiveObject();
    if (!active || isWallOrCorner(active)) {
      return;
    }
    copied = await active.clone(['name', 'hasControls']);
  }

  /** Paste operation */
  async function paste() {
    if (!copied || ctxRef.current.roomEdit) {
      return;
    }
    const cloned = await copied.clone(['name', 'hasControls']);
    view.discardActiveObject();
    cloned.set({
      left: cloned.left + RL_AISLEGAP,
      top: cloned.top + RL_AISLEGAP,
    });
    if (cloned.type === 'activeSelection') {
      cloned.canvas = view;
      (cloned as ActiveSelection).forEachObject((obj: FabricObject) => view.add(obj));
      cloned.setCoords();
    } else {
      view.add(cloned);
    }
    copied.top += RL_AISLEGAP;
    copied.left += RL_AISLEGAP;
    view.setActiveObject(cloned);
    view.requestRenderAll();
    saveState();
  }

  /** Delete operation */
  function deleteOp() {
    if (ctxRef.current.roomEdit) {
      return;
    }
    const deletable = selections.filter(selection => !isWallOrCorner(selection));
    if (deletable.length === 0) {
      return;
    }
    deletable.forEach(selection => view.remove(selection));
    view.discardActiveObject();
    view.requestRenderAll();
    saveState();
  }

  /** Rotate Operation */
  function rotate(clockwise = true) {
    if (ctxRef.current.roomEdit) {
      return;
    }

    let angle = CTRL_KEY_DOWN ? 90 : 15;
    const obj = view.getActiveObject();

    if (!obj || isWallOrCorner(obj)) { return; }

    if ((obj.originX !== 'center' || obj.originY !== 'center') && obj.centeredRotation) {
      obj.originX = 'center';
      obj.originY = 'center';
      obj.left += obj.width / 2;
      obj.top += obj.height / 2;
    }

    if (isDW(obj)) {
      angle = obj.angle + (clockwise ? 180 : -180);
    } else {
      angle = obj.angle + (clockwise ? angle : -angle);
    }

    if (angle > 360) { angle -= 360; } else if (angle < 0) { angle += 360; }

    obj.angle = angle;
    view.requestRenderAll();
  }

  /** Group */
  function group() {
    if (ctxRef.current.roomEdit) {
      return;
    }

    if (selections.some(isWallOrCorner)) {
      return;
    }

    const active = view.getActiveObject();
    if (!(selections.length > 1 && active instanceof ActiveSelection)) {
      return;
    }

    const objects = active.getObjects();
    const groupObj = new Group(objects);
    view.remove(...objects);
    view.add(groupObj);
    view.setActiveObject(groupObj);
    applyFabricTransformLocks(groupObj);
    onSelected();
    view.renderAll();
    saveState();
  }

  function ungroup() {
    if (ctxRef.current.roomEdit) {
      return;
    }

    if (selections.some(isWallOrCorner)) {
      return;
    }

    const active = view.getActiveObject();
    if (!(active && active instanceof Group)) {
      return;
    }

    const items = active.removeAll();
    view.remove(active);
    items.forEach((obj) => view.add(obj));
    const sel = new ActiveSelection(items, { canvas: view });
    view.setActiveObject(sel);
    view.getActiveObjects().forEach((obj) => applyFabricTransformLocks(obj));
    onSelected();
    view.renderAll();
    saveState();
  }

  function move(direction: string, increament = 6) {
    if (ctxRef.current.roomEdit) {
      return;
    }

    const active = view.getActiveObject();
    if (!active || isWallOrCorner(active)) {
      return;
    }
    switch (direction) {
      case 'LEFT':
        active.left -= increament;
        break;
      case 'UP':
        active.top -= increament;
        break;
      case 'RIGHT':
        active.left += increament;
        break;
      case 'DOWN':
        active.top += increament;
        break;
    }
    view.requestRenderAll();
    saveState();
  }

  const SCENE_WIDTH = RL_VIEW_WIDTH * RL_FOOT;
  const SCENE_HEIGHT = RL_VIEW_HEIGHT * RL_FOOT;

  function setZoom(zoomPct: number) {
    if (!view) return;
    const clamped = Math.max(20, Math.min(150, Math.round(zoomPct)));
    ctxRef.current.zoom = clamped;
    view.setDimensions({ width: SCENE_WIDTH, height: SCENE_HEIGHT });
    view.setZoom(clamped / 100);
    view.calcOffset();
    view.requestRenderAll();
    
    const canvasContainer = document.querySelector('[data-testid="planner-2d-canvas"]');
    if (canvasContainer) {
      canvasContainer.setAttribute('data-zoom', String(clamped));
    }
  }

  function setLayerVisibility(layerVisible: Record<string, boolean>) {
    if (!view) return;
    view.getObjects().forEach((obj) => {
      const category = resolveLayerCategory(obj);
      if (!category) return;
      const visible = layerVisible[category] !== false;
      obj.visible = visible;
      obj.evented = visible;
      if (!visible && view.getActiveObject() === obj) {
        view.discardActiveObject();
      }
    });
    view.requestRenderAll();
  }

  const FABRIC_TO_MM = 10;

  function resizeObject(shapeId: string, widthMm: number, heightMm: number) {
    if (!view) return;
    const target = view.getObjects().find((obj) => String((obj as PlannerFabricObject).id ?? (obj as PlannerFabricObject).name ?? '') === shapeId);
    if (!target) return;
    const newWidth = widthMm / FABRIC_TO_MM;
    const newHeight = heightMm / FABRIC_TO_MM;
    if (target instanceof Group) {
      target.set({
        scaleX: newWidth / Math.max(0.1, target.width),
        scaleY: newHeight / Math.max(0.1, target.height),
      });
    } else {
      target.set({
        width: newWidth,
        height: newHeight,
      });
    }
    target.setCoords();
    view.requestRenderAll();
    saveState();
  }

  function setObjectRotation(shapeId: string, angleDeg: number) {
    if (!view) return;
    const target = view.getObjects().find((obj) => String((obj as PlannerFabricObject).id ?? (obj as PlannerFabricObject).name ?? '') === shapeId);
    if (!target) return;
    
    if ((target.originX !== 'center' || target.originY !== 'center') && target.centeredRotation) {
      target.originX = 'center';
      target.originY = 'center';
      target.left += target.width / 2;
      target.top += target.height / 2;
    }
    
    target.angle = angleDeg;
    target.setCoords();
    view.requestRenderAll();
    saveState();
  }

  function setObjectLock(shapeId: string, locked: boolean) {
    if (!view) return;
    const target = view.getObjects().find((obj) => String((obj as PlannerFabricObject).id ?? (obj as PlannerFabricObject).name ?? '') === shapeId);
    if (!target) return;
    
    target.set({
      selectable: !locked,
      evented: !locked,
      lockMovementX: locked,
      lockMovementY: locked,
      lockRotation: locked,
      lockScalingX: locked,
      lockScalingY: locked,
    });
    if (locked && view.getActiveObject() === target) {
      view.discardActiveObject();
    }
    view.requestRenderAll();
    saveState();
  }

  function fitToStage() {
    if (!view || !canvasEl) return ctxRef.current.zoom;
    const wrap = canvasEl.closest('.canvas-wrap') as HTMLElement | null;
    if (!wrap) return ctxRef.current.zoom;

    const pad = 32;
    const availW = wrap.clientWidth - pad;
    const availH = wrap.clientHeight - pad;
    // Hidden view-stack panes collapse to ~0 width — never shrink zoom from that.
    if (availW < 280 || availH < 200) return ctxRef.current.zoom;

    const scale = Math.min(availW / SCENE_WIDTH, availH / SCENE_HEIGHT, 1);
    const zoomPct = Math.max(50, Math.min(150, Math.round(scale * 100)));
    setZoom(zoomPct);
    return zoomPct;
  }

  function zoomToPointer(nativeEvent: WheelEvent) {
    if (!view) return;

    const rect = view.lowerCanvasEl.getBoundingClientRect();
    const anchor = new Point(nativeEvent.clientX - rect.left, nativeEvent.clientY - rect.top);
    const nextZoom = Math.max(0.2, Math.min(1.5, view.getZoom() * Math.pow(0.999, nativeEvent.deltaY)));
    const nextZoomPct = Math.round(nextZoom * 100);

    nativeEvent.preventDefault();
    nativeEvent.stopPropagation();
    view.zoomToPoint(anchor, nextZoom);
    ctxRef.current.zoom = nextZoomPct;
    ctxRef.current.syncZoom(nextZoomPct);
    view.calcOffset();
    view.requestRenderAll();
  }

  function setGridVisible(enabled: boolean) {
    ctxRef.current.gridEnabled = enabled;
    syncGrid();
  }

  function placeInCenter(direction: string) {
    const active = view.getActiveObject();

    if (!active) {
      return;
    }

    if (direction === 'HORIZONTAL') {
      active.left = ROOM_SIZE.width / 2 - (active.originX === 'center' ? 0 : active.width / 2);
    } else {
      active.top = ROOM_SIZE.height / 2 - (active.originX === 'center' ? 0 : active.height / 2);
    }

    active.setCoords();
    view.requestRenderAll();
    saveState();
  }

  function arrange(action: string) {
    const rect = getBoundingRect(selections);
    action = action.toLowerCase();
    selections.forEach((s: FabricObject) => {
      if (action === 'left' || action === 'right' || action === 'center') {
        s.left = rect[action as keyof typeof rect];
      } else {
        s.top = rect[action as keyof typeof rect];
      }
    });
    view.renderAll();
    saveState();
  }

  function filterObjects(names: string[]) {
    return view.getObjects().filter((obj) => {
      const name = String((obj as PlannerFabricObject).name ?? '');
      return names.some((n) => name.includes(n));
    });
  }

  function isDW(object: unknown) {
    const name = String((object as PlannerFabricObject)?.name ?? '');
    return name.includes('DOOR') || name.includes('WINDOW');
  }

  function withExportFrame<T>(run: () => T): T {
    const { right, bottom } = getBoundingRect(corners);
    const width = view.getWidth();
    const height = view.getHeight();

    view.setDimensions({
      width: right + RL_ROOM_OUTER_SPACING,
      height: bottom + RL_ROOM_OUTER_SPACING + 12,
    });
    view.backgroundColor = 'white';

    const credit = new FabricText(RL_CREDIT_TEXT,
      {
        ...RL_CREDIT_TEXT_PARAMS,
        left: RL_ROOM_OUTER_SPACING,
        top: bottom + RL_ROOM_OUTER_SPACING - RL_CREDIT_TEXT_PARAMS.fontSize
      }
    );
    view.add(credit);
    view.discardActiveObject();
    view.renderAll();

    try {
      return run();
    } finally {
      view.remove(credit);
      view.setDimensions({ width, height });
      syncGrid();
    }
  }

  function exportSvg() {
    if (!view || corners.length === 0) return null;
    return withExportFrame(() => view.toSVG());
  }

  function exportPngBlob(): Promise<Blob | null> {
    if (!view || corners.length === 0) {
      return Promise.resolve(null);
    }

    return new Promise((resolve) => {
      withExportFrame(() => {
        const canvasEl = view.lowerCanvasEl;
        canvasEl.toBlob((blob: Blob | null) => resolve(blob));
      });
    });
  }

  function saveAs(format: string) {

    if (format === 'PNG') {
      void exportPngBlob().then((blob) => {
        if (!blob) return;
        saveFile(blob, `room_layout_${formatDate(new Date(), 'yyyy-MM-dd-hh-mm-ss', 'en')}.png`);
      });
    } else if (format === 'SVG') {
      const svg = exportSvg();
      if (!svg) return;
      const blob = new Blob([svg], { type: 'image/svg+xml;charset=utf-8' });
      saveFile(blob, `room_layout_${formatDate(new Date(), 'yyyy-MM-dd-hh-mm-ss', 'en')}.svg`);
    }
  }


  function dispose() {
    drawToolsController?.dispose?.();
    drawToolsController = null;
    if (view && !view.destroyed) {
      view.dispose();
    }
  }

  function setDrawTool(tool: FabricDrawTool) {
    drawTool = tool;
    drawToolsController?.setDrawTool(tool);
  }

  function setDrawColor(color: string) {
    drawColor = color;
    drawToolsController?.setDrawColor(color);
  }

  function setDrawFillColor(color: string) {
    drawFillColor = color;
    drawToolsController?.setDrawFillColor?.(color);
  }

  function setContextMenuListener(listener: ((state: FabricContextMenuState | null) => void) | null) {
    contextMenuListener = listener;
  }

  function applyStrokeToSelection(color: string) {
    if (ctxRef.current.roomEdit || !view) return;
    const active = view.getActiveObject();
    if (!active || !canEditFabricFill(active)) return;
    active.set('stroke', color);
    view.requestRenderAll();
    saveState();
  }

  function applyFillToSelection(color: string) {
    if (ctxRef.current.roomEdit || !view) return;
    const active = view.getActiveObject();
    if (!active || !canEditFabricFill(active)) return;
    active.set('fill', color === 'transparent' ? 'transparent' : color);
    view.requestRenderAll();
    saveState();
  }

  const api: FloorplanCanvasApi & {
    init: () => void;
    onKeyDown: (e: KeyboardEvent) => void;
    onKeyUp: (e: KeyboardEvent) => void;
    dispose: () => void;
  } = {
    init,
    onKeyDown,
    onKeyUp,
    dispose,
    undo,
    redo,
    copy,
    paste,
    delete: deleteOp,
    rotate,
    group,
    ungroup,
    placeInCenter,
    arrange,
    setZoom,
    setGridVisible,
    exportState,
    importState,
    exportSvg,
    exportPngBlob,
    saveAs,
    handleInsert: handleObjectInsertion,
    editRoom,
    cancelRoomEdition,
    setDrawTool,
    setDrawColor,
    setDrawFillColor,
    applyStrokeToSelection,
    applyFillToSelection,
    setContextMenuListener,
    fitToStage,
    recalcOffset: () => view?.calcOffset(),
    setLayerVisibility,
    resizeObject,
    setObjectRotation,
    setObjectLock,
  };
  return api;
}

"use client";

import { useState } from "react";
import { LayoutGrid, PanelLeftClose, Sparkles, type LucideIcon } from "lucide-react";

import { AIAssistDrawer } from "@/features/planner/ai/AIAssistDrawer";
import { CatalogPanel } from "@/features/planner/catalog/CatalogPanel";
import type { CatalogItem } from "@/features/planner/catalog/catalogTypes";
import type { MeasurementUnit } from "@/features/planner/lib/measurements";
import type { PlannerStep } from "@/features/planner/editor/plannerStep";

import { getStepLeftEmphasis } from "@/features/planner/editor/usePlannerPanels";
import { getStepLeftTab, type PlannerLeftTab } from "./plannerStepBindings";

const TAB_META: Record<PlannerLeftTab, { label: string; Icon: LucideIcon }> = {
  library: { label: "Library", Icon: LayoutGrid },
  "ai-assist": { label: "AI Assist", Icon: Sparkles },
};

function getTabsForStep(step: PlannerStep): PlannerLeftTab[] {
  switch (step) {
    case "draw":
      return ["library", "ai-assist"];
    case "place":
      return ["library", "ai-assist"];
    case "review":
      return ["ai-assist", "library"];
    default:
      return ["library", "ai-assist"];
  }
}

function getStepNote(step: PlannerStep, tab: PlannerLeftTab): string {
  switch (step) {
    case "draw":
      return tab === "library"
        ? "Browse Oando SVG symbols — click or drag desks, seating, and storage onto the canvas."
        : tab === "ai-assist"
          ? "Use AI for layout ideas, then return to Library to keep editing."
          : "Start from a blank canvas or open a template before placing products.";
    case "place":
      return tab === "ai-assist"
          ? "Use AI for arrangement ideas, then place products directly on the canvas."
          : "Use the library for furniture, then place doors and windows on the canvas.";
    case "review":
      return "Review measurements, properties, and export on the right. Jump back to Draw or Place anytime.";
    default:
      return "";
  }
}

interface PlannerLeftPanelProps {
  guestMode: boolean;
  editor?: null;
  plannerStep?: PlannerStep;
  panelOpen?: boolean;
  panelCollapsed?: boolean;
  showPanelToggle?: boolean;
  onTogglePanel?: () => void;
  activeTab?: PlannerLeftTab;
  onTabChange?: (tab: PlannerLeftTab) => void;
  onItemClick: (item: CatalogItem) => void;
  onDragStart: (item: CatalogItem) => void;
  onDragEnd?: () => void;
  unitSystem?: MeasurementUnit;
}

export function PlannerLeftPanel({
  guestMode,
  editor = null,
  plannerStep = "draw",
  panelOpen = true,
  panelCollapsed = false,
  showPanelToggle = false,
  onTogglePanel,
  activeTab,
  onTabChange,
  onItemClick,
  onDragStart,
  onDragEnd,
}: PlannerLeftPanelProps) {
  const [pickedTab, setPickedTab] = useState<PlannerLeftTab | null>(null);
  const [lastStep, setLastStep] = useState(plannerStep);

  if (lastStep !== plannerStep) {
    setLastStep(plannerStep);
    if (!activeTab) setPickedTab(null);
  }

  const tab = activeTab ?? pickedTab ?? getStepLeftTab(plannerStep);
  const stepNote = getStepNote(plannerStep, tab);
  const tabs = getTabsForStep(plannerStep);
  const primaryTab = tabs[0];
  const emphasis = getStepLeftEmphasis(plannerStep);

  const selectTab = (next: PlannerLeftTab) => {
    if (onTabChange) onTabChange(next);
    else setPickedTab(next);
  };

  return (
    <aside
      data-coach="catalog"
      data-step={plannerStep}
      data-open={panelOpen ? true : undefined}
      data-collapsed={panelCollapsed ? true : undefined}
      data-emphasis={emphasis}
      className="pw-left-panel"
      aria-label="Planner Sidebar"
    >
      <div className="pw-panel-tabs" role="tablist" aria-label="Left panel">
        {tabs.map((tabId) => {
          const { label, Icon } = TAB_META[tabId];
          return (
            <button
              key={tabId}
              type="button"
              role="tab"
              className="pw-panel-tab pwx-panel-tab"
              data-active={tab === tabId}
              data-relevant={tabId === primaryTab}
              data-collapsed={panelCollapsed || undefined}
              aria-selected={tab === tabId}
              aria-label={label}
              onClick={() => selectTab(tabId)}
            >
              <Icon size={14} strokeWidth={2} aria-hidden />
              <span>{label}</span>
            </button>
          );
        })}
        {showPanelToggle && onTogglePanel ? (
          <button
            type="button"
            className="pw-panel-collapse pw-icon-btn"
            onClick={onTogglePanel}
            aria-label="Close left panel"
          >
            <PanelLeftClose size={14} strokeWidth={2} aria-hidden />
          </button>
        ) : null}
      </div>
      <div className="pw-panel-body" data-active-tab={tab} hidden={panelCollapsed}>
        {tab !== "library" ? <p className="pw-panel-step-note">{stepNote}</p> : null}
        {tab === "library" ? (
          <CatalogPanel
            embedded
            onItemClick={onItemClick}
            onDragStart={onDragStart}
            onDragEnd={onDragEnd}
          />
        ) : (
          <AIAssistDrawer editor={editor} embedded defaultExpanded />
        )}
      </div>
    </aside>
  );
}

"use client";


import { FabricCanvasSubToolbar } from "@/features/planner/canvas-fabric/FabricCanvasSubToolbar";
import { ZoomControl } from "@/features/planner/canvas-fabric/components/ZoomControl";
import { useFloorplan } from "@/features/planner/canvas-fabric";

interface PlannerSubTopBarProps {
  viewMode: "2d" | "3d" | "split";
  onViewModeChange: (mode: "2d" | "3d" | "split") => void;
  leftCollapsed: boolean;
  rightCollapsed: boolean;
  onToggleLeftCollapsed?: () => void;
  onToggleRightCollapsed?: () => void;
  onResetLayout?: () => void;
  onOpenExport?: () => void;
}

export function PlannerSubTopBar({
  viewMode,
  onViewModeChange,
  leftCollapsed,
  rightCollapsed,
  onToggleLeftCollapsed,
  onToggleRightCollapsed,
  onResetLayout,
  onOpenExport,
}: PlannerSubTopBarProps) {
  const { zoom, setZoom } = useFloorplan();

  return (
    <div className="pw-subtopbar-shell">


      {viewMode !== "3d" ? <FabricCanvasSubToolbar onExport={onOpenExport} /> : null}

      <div className="pw-subtopbar pw-subtopbar--view" data-coach="view-toggle">
        <div className="pw-segment pw-segment--compact">
          {(["2d", "3d", "split"] as const).map((mode) => (
            <button
              key={mode}
              type="button"
              onClick={() => onViewModeChange(mode)}
              className="pw-segment-btn"
              data-active={viewMode === mode}
              aria-pressed={viewMode === mode}
            >
              {mode === "2d" ? "2D" : mode === "3d" ? "3D" : "Split"}
            </button>
          ))}
        </div>
        <ZoomControl zoom={zoom} onZoomChange={setZoom} />
      </div>
    </div>
  );
}

