    ),
    [viewMode],
  );

  const canvas3D = (
    <Suspense fallback={<PlannerSkeleton />}>
      <div className="pw-viewer-host h-full min-h-0 w-full">
        <PlannerErrorBoundary label="3D Viewer">
          <Planner3DViewer document={currentPlannerDocument} />
        </PlannerErrorBoundary>
      </div>
