export function countMeasurementShapes(): number {
  try {
    const serializedDraft = getPlannerFabricRuntimeState().serializedDraft;
    if (!serializedDraft) return 0;
    const snapshot = JSON.parse(serializedDraft) as { objects?: any[] };
    const objects = snapshot.objects;
    if (!Array.isArray(objects)) return 0;
    return objects.filter((obj: any) => String(obj.name || "").startsWith("DRAW:measure")).length;
  } catch {
    return 0;
  }
}

export function evaluatePlannerStepGates(
  _editor: null,
  metrics: PlanMetrics,
): PlannerStepGates {
  const measurementCount = countMeasurementShapes();
  const hasSpaceShell =
    metrics.wallCount > 0 || metrics.roomAreaSqm > 0 || metrics.zoneAreaSqm > 0;
  const hasFurniture = metrics.furnitureCount > 0;
  const hasMeasurement = metrics.wallCount > 0 || measurementCount > 0;

  return {
    hasSpaceShell,
    hasFurniture,
    hasMeasurement,
    measurementCount,
    canOpenExport: hasFurniture && hasSpaceShell,
  };
}

export function getDisabledPlannerSteps(gates: PlannerStepGates): Partial<Record<PlannerStep, boolean>> {
  void gates;
  return {};
}

export function getPlannerStepHint(step: PlannerStep, gates: PlannerStepGates): string {
  switch (step) {
    case "draw":
      return gates.hasSpaceShell
        ? "Space shell is ready. Keep refining walls and rooms, or jump to Place to add products."
        : "Start by drawing walls and rooms to define the space.";
    case "place":
      return gates.hasFurniture
        ? "Furniture and openings are in place. Keep arranging, or jump to Review for dimensions and export."
        : "Use the library for furniture, then place doors and windows directly on the canvas.";
    case "review":
      return gates.canOpenExport
        ? "Measurements, properties, and export are ready whenever you are."
        : "Review measurements and properties here. Export unlocks once the space shell and furniture are in place.";
    default:
      return "";
  }
}

export function getPlannerStepActionLabel(step: PlannerStep): string {
  switch (step) {
    case "draw":
      return "Go to Place";
    case "place":
      return "Go to Review";
    case "review":
      return "Open Export";
    default:
      return "Continue";
  }
}

export function canAdvancePlannerStep(step: PlannerStep, gates: PlannerStepGates): boolean {
  switch (step) {
    case "draw":
    case "place":
      return true;
    case "review":
      return gates.canOpenExport;
    default:
      return false;
  }
}

export function previousPlannerStep(step: PlannerStep): PlannerStep | null {
  const index = PLANNER_STEPS.indexOf(step);
  if (index <= 0) return null;
  return PLANNER_STEPS[index - 1] ?? null;
}

export function nextPlannerStep(step: PlannerStep): PlannerStep | null {
  const index = PLANNER_STEPS.indexOf(step);
  if (index < 0 || index >= PLANNER_STEPS.length - 1) return null;
  return PLANNER_STEPS[index + 1] ?? null;
}

import { useCallback, useEffect, useRef, useState } from "react";
import type { CatalogItem } from "@/features/planner/catalog/catalogTypes";
import { useFloorplan } from "@/features/planner/canvas-fabric/context/FloorplanContext";
import type { PlannerToolBinding } from "./plannerKeyboardShortcuts";
import { usePlannerStore } from "@/features/planner/store/plannerStore";

export function usePlannerViewMode() {
  const [viewMode, setViewMode] = useState<"2d" | "3d" | "split">("2d");

  const handleViewModeChange = useCallback((mode: "2d" | "3d" | "split") => {
    setViewMode(mode);
  }, []);

  return { viewMode, handleViewModeChange, setViewMode };
}

export function usePlannerCatalogDrop(canvasSurfaceRef: React.RefObject<HTMLDivElement>) {
  const [dragItem, setDragItem] = useState<CatalogItem | null>(null);
  const [isCatalogOverCanvas, setIsCatalogOverCanvas] = useState(false);
  const { insertObject } = useFloorplan();

  const handleCanvasDragOver = useCallback((e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    const item = (e.dataTransfer as any).catalogItem;
    if (item) {
      setIsCatalogOverCanvas(true);
      setDragItem(item);
    }
  }, []);

  const handleCanvasDrop = useCallback(
    (e: React.DragEvent<HTMLDivElement>) => {
      e.preventDefault();
      e.stopPropagation();
      setIsCatalogOverCanvas(false);
      const item = (e.dataTransfer as any).catalogItem;
      if (item) {
        insertObject({
          type: "CATALOG",
          object: { catalogItemId: item.id },
        });
      }
      setDragItem(null);
    },
    [insertObject]
  );

  return {
    dragItem,
    isCatalogOverCanvas,
    handleCanvasDragOver,
    handleCanvasDrop,
    setDragItem,
    setIsCatalogOverCanvas,
  };
}

export function usePlannerDocument() {
  const { exportDraft, importDraft } = useFloorplan();

  const saveDocument = useCallback(async (name: string) => {
    const state = exportDraft();
    if (!state) return null;
    return { name, data: state, timestamp: Date.now() };
  }, [exportDraft]);

  const loadDocument = useCallback(
    async (data: string) => {
      await importDraft(data);
    },
    [importDraft]
  );

  return { saveDocument, loadDocument };
}

export function usePlannerKeyboardHandlers(applyToolBinding: (binding: PlannerToolBinding) => void) {
  const handleKeyDown = useCallback(
    (e: KeyboardEvent) => {
      if (e.ctrlKey || e.metaKey || e.shiftKey || e.altKey) return;
      const bindings: Record<string, PlannerToolBinding> = {
        w: { toolId: "planner-wall", plannerTool: "wall" },
        v: { toolId: "select", plannerTool: "select" },
      };
      const binding = bindings[e.key.toLowerCase()];
      if (binding) {
        e.preventDefault();
        applyToolBinding(binding);
      }
    },
    [applyToolBinding]
  );

  useEffect(() => {
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [handleKeyDown]);
}

