      seatCount: 5,
      floorAreaSqFt: 1500,
      purpose: "open-office",
    };
    const layout = suggestLayoutGridPack(input);
    applySuggestedLayout(null, layout);

    const genericObjects = insertedObjects.filter((obj) => obj.type === "GENERIC");
